  )
  expect_equal(
    native_q2_slope$denominator_policy,
    rep("fixture_not_coverage", 4L)
  )
  structured_re_expect_all_match(
    native_q2_slope$formula_cell,
    "0 + x | p",
    fixed = TRUE
  )
  structured_re_expect_all_match(
    native_q2_slope$claim_boundary,
