    fixed = TRUE
  )
  expect_equal(
    native_q2_slope$evidence_url,
    ifelse(
      native_q2_slope$structure_provider %in% c("spatial", "animal"),
      "docs/dev-log/dashboard/structured-re-q2-slope-bias-t-topup-results.tsv",
