    "q2",
    "q4/q8",
    "non-Gaussian",
    "REML",
    "AI-REML",
    "public support"
  )) {
    structured_re_expect_all_match(shape$claim_boundary, phrase)
  }
  for (phrase in c("Fisher/Rose", "new interval-shape", "DRAC")) {
    structured_re_expect_all_match(shape$next_gate, phrase)
  }
})

