test_that("Tranche 55 q1 mu one-slope interval-rule hold keeps route non-executable", {
  hold <- structured_re_read_dashboard_tsv(
    "structured-re-gaussian-mu-slope-tranche55-interval-rule-hold-decision.tsv"
  )
  qseries <- structured_re_read_dashboard_tsv(
    "structured-re-q-series-support-cells.tsv"
  )
  discussions <- structured_re_read_dashboard_tsv("member-discussions.tsv")

  expect_named(
    hold,
    c(
      "decision_id",
      "decision_scope",
      "cell_id",
      "provider",
      "source_review_decision",
      "source_interval_shape",
      "source_rule_screen",
      "source_split_calibration",
      "evidence_status",
      "held_route",
      "decision_status",
      "compute_decision",
      "coverage_decision",
      "promotion_decision",
      "support_cell_decision",
      "blocking_reviewers",
      "advisory_reviewers",
      "fisher_review",
      "rose_audit",
      "noether_review",
      "curie_review",
      "grace_review",
      "evidence_url",
      "claim_boundary",
      "next_gate"
    )
  )
  expect_equal(nrow(hold), 8L)
  expect_equal(
    hold$decision_id,
    c(
      "tranche55_mu_slope_phylo_rule_hold",
      "tranche55_mu_slope_spatial_rule_hold",
      "tranche55_mu_slope_animal_rule_hold",
      "tranche55_mu_slope_relmat_rule_hold",
      "tranche55_mu_slope_current_rule_block",
      "tranche55_mu_slope_ad_hoc_multiplier_reject",
      "tranche55_mu_slope_split_calibration_reject",
      "tranche55_mu_slope_tranche_summary"
    )
  )
  expect_equal(
    hold$decision_scope,
    c(
      "provider_hold",
      "provider_hold",
      "provider_hold",
      "provider_hold",
      "current_rule_block",
      "ad_hoc_multiplier_reject",
      "split_calibration_hold",
      "tranche_summary"
    )
  )
  expect_equal(
    hold$cell_id[hold$decision_scope == "provider_hold"],
    c(
      "qseries_phylo_q1_mu_one_slope",
      "qseries_spatial_q1_mu_one_slope",
      "qseries_animal_q1_mu_one_slope",
      "qseries_relmat_q1_mu_one_slope"
    )
  )
  structured_re_expect_all_match(
    hold$held_route,
    "principled_skew_or_boundary_aware_interval_rule_required"
  )
  structured_re_expect_all_match(
    hold$decision_status,
    "route_hold_no_executable_rule_selected"
  )
  structured_re_expect_all_match(hold$compute_decision, "no_compute_in_tranche55")
  structured_re_expect_all_match(
    hold$coverage_decision,
    "coverage_not_authorized"
  )
  structured_re_expect_all_match(hold$promotion_decision, "do_not_promote")
  structured_re_expect_all_match(
    hold$support_cell_decision,
    "leave_point_fit_extractor_ready_fixture_parity_planned_planned_source"
  )
  structured_re_expect_all_match(
    hold$blocking_reviewers,
    "rose;fisher;noether;grace"
  )
  structured_re_expect_all_match(
    hold$advisory_reviewers,
    "curie;ada;boole;emmy"
  )

  for (path in unique(c(
    hold$source_review_decision,
    hold$source_interval_shape,
    hold$source_rule_screen,
    hold$source_split_calibration,
    hold$evidence_url
  ))) {
    expect_true(file.exists(
      structured_re_artifact_path(strsplit(path, "/", fixed = TRUE)[[1L]])
    ))
  }

  for (phrase in c(
    "Tranche 55 q1 mu one-slope interval-rule hold only",
    "current hybrid interval remains upper-tail blocked",
    "ad hoc widening multipliers are not accepted as a support route",
    "split calibration is diagnostic only",
    "no executable interval rule selected",
    "no retained-artifact replay run in this tranche",
    "no Totoro command",
    "no FIIA command",
    "no Nibi/Rorqual/Trillium/DRAC submission",
    "no top-up",
    "no coverage result",
    "no support-cell status movement",
    "no interval_status",
    "no coverage_status",
    "no inference_ready",
    "no supported",
    "no q1 sigma",
    "no matched mu+sigma",
    "no q2",
    "no q4/q8",
    "no non-Gaussian interval",
    "no REML",
    "no AI-REML",
    "no bridge support",
    "no public support",
    "linked support cells remain point_fit/extractor_ready/fixture_parity/planned/planned/source"
  )) {
    structured_re_expect_all_match(hold$claim_boundary, phrase)
  }
  structured_re_expect_all_match(
    hold$next_gate[hold$decision_scope %in% c(
      "provider_hold",
      "current_rule_block",
      "tranche_summary"
    )],
    "symbolic"
  )
  structured_re_expect_all_match(
    hold$next_gate[hold$decision_scope %in% c(
      "provider_hold",
      "current_rule_block",
      "tranche_summary"
    )],
    "retained"
  )
  expect_match(
    hold$next_gate[hold$decision_scope == "ad_hoc_multiplier_reject"],
    "before any host command",
    fixed = TRUE
  )
  expect_match(
    hold$next_gate[hold$decision_scope == "split_calibration_hold"],
    "do not smoke or top up",
    fixed = TRUE
  )

  cells <- c(
    "qseries_phylo_q1_mu_one_slope",
    "qseries_spatial_q1_mu_one_slope",
    "qseries_animal_q1_mu_one_slope",
    "qseries_relmat_q1_mu_one_slope"
  )
  linked <- qseries[match(cells, qseries$cell_id), ]
  expect_equal(linked$fit_status, rep("point_fit", 4L))
  expect_equal(linked$extractor_status, rep("extractor_ready", 4L))
  expect_equal(linked$bridge_status, rep("fixture_parity", 4L))
  expect_equal(linked$interval_status, rep("planned", 4L))
  expect_equal(linked$coverage_status, rep("planned", 4L))
  expect_equal(linked$authority_status, rep("source", 4L))

  meeting <- discussions[
    discussions$meeting_id ==
      "meeting-2026-07-02-tranche55-mu-slope-interval-rule-hold" &
      discussions$slice_id == "SC399",
  ]
  expect_setequal(
    meeting$member_id,
    c("ada", "rose", "fisher", "noether", "grace", "curie", "boole", "emmy")
  )
  expect_true(all(
    meeting$evidence_path == paste0(
      "docs/dev-log/dashboard/",
      "structured-re-gaussian-mu-slope-tranche55-interval-rule-hold-decision.tsv"
    )
  ))
  blocking <- meeting$member_id %in% c("rose", "fisher", "noether", "grace")
  expect_equal(meeting$stance[blocking], rep("block_until_done", sum(blocking)))
  expect_equal(meeting$stance[!blocking], rep("approve", sum(!blocking)))
  expect_equal(meeting$decision_status, rep("accepted", nrow(meeting)))
})

