    rep(475L, 6L)
  )
  for (phrase in c(
    "Tranche 57 local retained replay builder only",
    "no executable interval rule",
    "no Totoro command",
    "no FIIA command",
    "no Nibi/Rorqual/Trillium/DRAC command",
