  expect_equal(source_index$source_status, rep("source_resolved", nrow(source_index)))
  expect_equal(nrow(detail), 3303L)
  expect_setequal(
    detail$row_kind,
    c(
      "wald_replicate",
      "profile_boundary_detail",
      "diagnostic_rule_screen_targets",
      "diagnostic_split_calibration_targets"
    )
  )
  expect_true(all(detail$host_label %in% c("local", "local_dashboard")))
  expect_equal(
    as.character(detail$include_in_replay_denominator) == "TRUE",
    detail$row_kind == "wald_replicate"
  )
  expect_equal(nrow(run_log), 1L)
  expect_equal(run_log$run_scope, "local_retained_artifact_replay_builder_only")
  expect_equal(run_log$detail_rows, 3303L)
  expect_equal(run_log$summary_rows, 9L)
  expect_equal(run_log$coverage_decision, "coverage_not_authorized")
  expect_match(run_log$claim_boundary, "no fit", fixed = TRUE)
  expect_match(run_log$claim_boundary, "no simulation", fixed = TRUE)

  cells <- c(
    "qseries_phylo_q1_mu_one_slope",
