    "host_denominator_separate"
  )) {
    structured_re_expect_all_match(planned_rows$denominator_policy, phrase)
  }
  zero_rows <- runner_gate[runner_gate$planned_n_rep == "0", ]
  expect_equal(nrow(zero_rows), 3L)
  expect_equal(zero_rows$planned_seed_set, rep("none", 3L))
  expect_equal(zero_rows$host_label_policy, rep("none", 3L))

  for (phrase in c(
    "Tranche 62 spatial-only dry-run runner gate only",
    "execution disabled by default",
