  )
  structured_re_expect_all_match(runner_gate$next_gate, "no host command")

  expect_true(file.exists(runner_path))
  expect_silent(parse(runner_path))
  rscript <- file.path(R.home("bin"), "Rscript")
  dry_run <- system2(
    rscript,
    c(
      "--no-init-file",
      runner_arg,
      "--target=both",
      "--provider=spatial",
      "--n-rep=5",
      "--seeds=861001,861002,861003,861004,861005",
      "--write-dashboard=false",
      "--execution-approved=false"
    ),
    stdout = TRUE,
    stderr = TRUE
  )
  expect_null(attr(dry_run, "status"))
  manifest <- utils::read.delim(
    text = paste(dry_run, collapse = "\n"),
    check.names = FALSE
  )
  expect_named(
    manifest,
    c(
      "dry_run_id",
      "provider",
      "target",
      "endpoint_member",
      "direct_sd_target",
      "replicate_index",
      "seed",
      "host_label",
      "execution_status",
      "denominator_status",
      "coverage_decision",
      "promotion_decision",
      "support_cell_decision",
      "claim_boundary"
    )
  )
