  expect_equal(ncol(manifest), 14L)
  expect_equal(unique(manifest$provider), "spatial")
  expect_equal(sort(unique(manifest$target)), c("mu_intercept", "mu_x"))
  target_counts <- table(manifest$target)
  expect_equal(names(target_counts), c("mu_intercept", "mu_x"))
  expect_equal(as.integer(target_counts), c(5L, 5L))
  expect_equal(
    manifest$seed,
    rep(861001:861005, 2L)
  )
  expect_equal(
    manifest$execution_status,
    rep("dry_run_only_no_fit_no_host_command", 10L)
  )
  expect_equal(manifest$denominator_status, rep("no_new_denominator", 10L))
  expect_equal(
    manifest$coverage_decision,
    rep("coverage_not_authorized", 10L)
  )
  expect_equal(manifest$promotion_decision, rep("do_not_promote", 10L))
  expect_equal(
    manifest$support_cell_decision,
    rep("unchanged_point_fit_planned_planned", 10L)
  )

  refusal <- suppressWarnings(system2(
    rscript,
    c(
      "--no-init-file",
      runner_arg,
      "--target=both",
      "--provider=spatial",
      "--n-rep=5",
