    rep("reject_for_linux_load_route_compiled_macos_arm64_artifact", 3L)
  )
  expect_true(all(grepl(snapshot_path, compiled$path, fixed = TRUE)))
  expect_setequal(
    compiled$sha256,
    c(
      "35e8581b0c2c43759dbafc4c2fb96532db630b050107c368635d5407ba049476",
      "af55564bc2acae0f10f6a39af2959f0bbd60e48625f9b4a3fd12bd8562cd6355",
      "bd47dda1c34455b18e513812390c9139d0b458eb4414e7bf75918f63771ce84e"
    )
  )

  transport <- utils::read.delim(
    transport_path,
    sep = "\t",
    quote = "",
    check.names = FALSE,
    stringsAsFactors = FALSE
  )
  expect_equal(nrow(transport), 4L)
  expect_setequal(
    transport$artifact_id,
