      "._run-gaussian-mu-slope-tranche70-spatial-host-smoke.sh"
    )
  )
  expect_equal(transport$presence, rep("present", 4L))
  payload <- transport[!grepl("^\\._", transport$artifact_id), ]
  apple <- transport[grepl("^\\._", transport$artifact_id), ]
