  expect_equal(gate$source_snapshot_path, rep(snapshot_path, 8L))
  expect_equal(gate$source_manifest_sha256, rep(manifest_hash, 8L))
  expect_equal(gate$source_provenance_sha256, rep(provenance_hash, 8L))
  expect_equal(as.character(gate$manifest_file_count), rep("16889", 8L))
  expect_equal(gate$run_root_path, rep(run_root, 8L))
  expect_equal(gate$host_label, rep(host_label, 8L))
  expect_equal(as.character(gate$planned_n_rep), rep("5", 8L))
  expect_equal(gate$planned_seed_set, rep("861001;861002;861003;861004;861005", 8L))
  expect_equal(gate$execution_approval_token_required, rep(token, 8L))
  expect_equal(
    gate$runner_contract_status,
    rep("fail_closed_t73_path_runner_contract_banked_no_execution", 8L)
  )
  expect_equal(
    gate$execution_decision,
    rep("dry_run_and_refusal_probes_only_no_model_execution", 8L)
  )
  expect_equal(gate$coverage_decision, rep("coverage_not_authorized", 8L))
  expect_equal(gate$promotion_decision, rep("do_not_promote", 8L))
  expect_equal(
    gate$support_cell_decision,
    rep("unchanged_point_fit_planned_planned", 8L)
  )
  for (phrase in c(
    "runner-path gate only",
    "exact T73 clean-source snapshot",
    "dry-run emits the 10 planned seed-target manifest rows",
    "no R package load",
    "no devtools load_all",
    "no model command",
    "no fit attempt",
    "no retained denominator",
    "no inference_ready",
    "no supported",
    "no denominator pooling",
    token
  )) {
    structured_re_expect_all_match(gate$claim_boundary, phrase)
  }
  for (phrase in c(
    "Tranche 75 at most one Totoro n5 smoke command",
    "Rose/Fisher/Gauss/Noether/Grace review",
    "T74 wrapper",
    "exact T73 source and run root",
    "exact seeds 861001-861005",
    "write-dashboard=false",
    "no pooled denominator",
    "stop before any coverage",
    "support-cell status edit"
  )) {
    structured_re_expect_all_match(gate$next_gate, phrase)
  }

  for (path in c(
    runner_file,
    wrapper_file,
    dry_run_path,
    dry_run_stderr_path,
    dry_run_exit_path,
    execute_stderr_path,
    execute_stdout_path,
    execute_exit_path,
    wrapper_stderr_path,
    wrapper_stdout_path,
    wrapper_exit_path,
    hash_path
  )) {
    expect_true(file.exists(path), info = path)
  }
  expect_equal(file.info(dry_run_stderr_path)$size, 0)
  expect_equal(file.info(execute_stdout_path)$size, 0)
  expect_equal(file.info(wrapper_stdout_path)$size, 0)
  expect_equal(readLines(dry_run_exit_path, warn = FALSE), "0")
  expect_equal(readLines(execute_exit_path, warn = FALSE), "1")
  expect_equal(readLines(wrapper_exit_path, warn = FALSE), "64")

  dry_run <- utils::read.delim(
    dry_run_path,
    sep = "\t",
    quote = "",
    check.names = FALSE,
    stringsAsFactors = FALSE
  )
  expect_equal(nrow(dry_run), 10L)
  expect_setequal(dry_run$target, c("mu_intercept", "mu_x"))
  expect_setequal(as.character(dry_run$seed), c("861001", "861002", "861003", "861004", "861005"))
  expect_equal(dry_run$provider, rep("spatial", 10L))
  expect_equal(dry_run$host_label, rep(host_label, 10L))
  expect_equal(dry_run$source_snapshot_path, rep(snapshot_path, 10L))
  expect_equal(dry_run$run_root_path, rep(run_root, 10L))
