  expect_equal(dry_run$denominator_status, rep("no_new_denominator", 10L))
  expect_equal(dry_run$coverage_decision, rep("coverage_not_authorized", 10L))
  expect_equal(dry_run$promotion_decision, rep("do_not_promote", 10L))
  expect_equal(
    dry_run$support_cell_decision,
    rep("unchanged_point_fit_planned_planned", 10L)
  )
  structured_re_expect_all_match(dry_run$claim_boundary, token)
  structured_re_expect_all_match(dry_run$claim_boundary, "exact T73 Totoro snapshot")
  structured_re_expect_all_match(dry_run$claim_boundary, "no model command in dry-run")

  execute_stderr <- paste(readLines(execute_stderr_path, warn = FALSE), collapse = "\n")
  expect_match(execute_stderr, "Refusing Tranche 74 execution", fixed = TRUE)
  expect_match(execute_stderr, token, fixed = TRUE)
  expect_match(execute_stderr, "Execution halted", fixed = TRUE)
  wrapper_stderr <- paste(readLines(wrapper_stderr_path, warn = FALSE), collapse = "\n")
  expect_match(wrapper_stderr, "Refusing Tranche 74 spatial q1 mu one-slope smoke", fixed = TRUE)
  expect_match(wrapper_stderr, token, fixed = TRUE)

  hash_text <- paste(readLines(hash_path, warn = FALSE), collapse = "\n")
  expect_match(hash_text, "857745b634b7720fd33725c804ce3f44eca8ca459d1437086d6217bc59403032  tools/run-gaussian-mu-slope-tranche74-spatial-host-smoke.R", fixed = TRUE)
  expect_match(hash_text, "4e73f387025823b31f44fa65b6737cac5691bbde62a74b5b36395881e3d8fd29  tools/run-gaussian-mu-slope-tranche74-spatial-host-smoke.sh", fixed = TRUE)
  expect_match(hash_text, "edf47caf8a90806c040a0447b5930a6917066510d5514fa76a9e690b6d181ea4", fixed = TRUE)
  expect_match(hash_text, "7c4cbf2643b191cfe21f4a168645c3db578adf6560a1827f302a4357ac11eca4", fixed = TRUE)
  expect_match(hash_text, "4f7d34335446ac329dff35daf374aa5bb3035c87aa3aac10f7357edc21155b9e", fixed = TRUE)

  runner_text <- paste(readLines(runner_file, warn = FALSE), collapse = "\n")
  expect_match(runner_text, "Tranche 74 fail-closed runner", fixed = TRUE)
  expect_match(runner_text, "Tranche 74 must use the exact T73 source snapshot path", fixed = TRUE)
  expect_match(runner_text, snapshot_path, fixed = TRUE)
  expect_match(runner_text, run_root, fixed = TRUE)
  expect_match(runner_text, "devtools_load_all_exact_t73_source_snapshot", fixed = TRUE)
  expect_match(runner_text, "phase18_fit_spatial_mu_slope", fixed = TRUE)
  expect_false(grepl("DRMTMB_Q1MU_SLOPE_T70_EXECUTION_APPROVED", runner_text, fixed = TRUE))
  expect_false(grepl("rose_fisher_noether_grace", runner_text, fixed = TRUE))

  wrapper_text <- paste(readLines(wrapper_file, warn = FALSE), collapse = "\n")
  expect_match(wrapper_text, token, fixed = TRUE)
  expect_match(wrapper_text, snapshot_path, fixed = TRUE)
  expect_match(wrapper_text, run_root, fixed = TRUE)
  expect_match(wrapper_text, host_label, fixed = TRUE)
  expect_match(wrapper_text, "--write-dashboard=false", fixed = TRUE)
  expect_false(grepl("DRMTMB_Q1MU_SLOPE_T70_EXECUTION_APPROVED", wrapper_text, fixed = TRUE))

  linked <- qseries[
    qseries$cell_id == "qseries_spatial_q1_mu_one_slope",
  ]
  expect_equal(nrow(linked), 1L)
  expect_equal(linked$fit_status, "point_fit")
  expect_equal(linked$extractor_status, "extractor_ready")
  expect_equal(linked$bridge_status, "fixture_parity")
  expect_equal(linked$interval_status, "planned")
  expect_equal(linked$coverage_status, "planned")
  expect_equal(linked$authority_status, "source")

  meeting <- discussions[
    discussions$meeting_id ==
      "meeting-2026-07-02-tranche74-mu-slope-spatial-runner-path-gate" &
      discussions$slice_id == "SC414",
  ]
  expect_setequal(
    meeting$member_id,
    c(
      "ada",
      "rose",
      "fisher",
      "gauss",
      "noether",
      "grace",
      "curie",
      "boole",
      "emmy"
    )
  )
  expect_true(all(
    meeting$evidence_path == paste0(
      "docs/dev-log/dashboard/",
      "structured-re-gaussian-mu-slope-tranche74-spatial-runner-path-gate.tsv"
    )
  ))
  blocking <- meeting$member_id %in% c("rose", "fisher", "gauss", "noether", "grace")
  expect_equal(meeting$stance[blocking], rep("block_until_done", sum(blocking)))
  expect_equal(meeting$stance[!blocking], rep("approve", sum(!blocking)))
  expect_equal(meeting$decision_status, rep("accepted", nrow(meeting)))
})

