  structured_re_expect_all_match(proof$claim_boundary, "ssh BatchMode reached rorqual2")
  structured_re_expect_all_match(proof$claim_boundary, "required source checkout path, run root, output directory, copied T77 runner, and copied T77 wrapper are missing")
