    "structured-re-gaussian-mu-slope-tranche123-spatial-drac-model-smoke-execution-approval-checkpoint.tsv"
  )
  review <- structured_re_read_dashboard_tsv(
    "structured-re-gaussian-mu-slope-tranche124-spatial-drac-model-smoke-execution-terminal-review.tsv"
  )
  qseries <- structured_re_read_dashboard_tsv(
    "structured-re-q-series-support-cells.tsv"
  )
  queue <- structured_re_read_dashboard_tsv(
    "structured-re-q-series-next-campaign-queue.tsv"
  )
  discussions <- structured_re_read_dashboard_tsv("member-discussions.tsv")

  expect_named(review, names(prior_review))
  expect_equal(nrow(review), 10L)
  expect_setequal(
    review$decision_id,
    c(
      "tranche124_spatial_mu_slope_job_submission",
      "tranche124_spatial_mu_slope_terminal_state",
      "tranche124_spatial_mu_slope_source_sha_guard",
      "tranche124_spatial_mu_slope_library_load_guard",
      "tranche124_spatial_mu_slope_devtools_dependency_drift",
      "tranche124_spatial_mu_slope_missing_result_proof",
      "tranche124_spatial_mu_slope_no_model_boundary",
      "tranche124_spatial_mu_slope_denominator_boundary",
      "tranche124_spatial_mu_slope_support_cell_status_hold",
      "tranche124_spatial_mu_slope_tranche_summary"
    )
  )
  expect_equal(review$decision_scope, rep("q1_mu_one_slope_spatial_drac_model_smoke_execution_terminal_review", 10L))
  expect_equal(review$source_decision_id, rep("tranche123_spatial_mu_slope_tranche_summary", 10L))
  expect_equal(review$cell_id, rep("qseries_spatial_q1_mu_one_slope", 10L))
  expect_equal(review$provider, rep("spatial", 10L))
  expect_equal(review$endpoint_member, rep("mu:(Intercept);mu:x", 10L))
  expect_equal(review$direct_sd_target, rep("sd_mu_intercept;sd_mu_x", 10L))
  expect_equal(review$source_sidecar_file, rep(structured_re_tranche123_mu_evidence(), 10L))
  expect_equal(as.character(review$job_id), rep("15112750", 10L))
  expect_equal(review$planned_drac_host, rep("rorqual_single_t124_execution_authorized", 10L))
  expect_equal(review$observed_rorqual_host, rep("rc31704", 10L))
  expect_equal(review$remote_exit_code, rep("FAILED_13_0", 10L))
  expect_equal(review$artifact_fetch_status, rep("fetched_terminal_artifacts_no_result_rows", 10L))
  expect_equal(review$module_load_status, rep("passed_StdEnv_2023_r_4_4_0", 10L))
  expect_equal(review$source_sha_status, rep("SOURCE_PROVENANCE_source_sha_full_matched_56add7f04fab7bec57a42e56eaeb090dff491863", 10L))
  expect_equal(review$dependency_probe_status, rep("devtools_available_FALSE_dependency_drift", 10L))
  expect_equal(review$missing_dependency_status, rep("devtools_missing_or_unloadable", 10L))
  expect_equal(review$load_status, rep("library_drmTMB_passed_before_devtools_stop", 10L))
  expect_equal(review$model_command_status, rep("not_started_devtools_dependency_stop_before_runner", 10L))
  expect_equal(review$denominator_status, rep("no_new_denominator", 10L))
  expect_equal(review$coverage_decision, rep("coverage_not_authorized", 10L))
  expect_equal(review$promotion_decision, rep("do_not_promote", 10L))
  expect_equal(review$support_cell_decision, rep("unchanged_point_fit_planned_planned", 10L))

  for (path in unique(c(
    review$source_sidecar_file,
    review$local_artifact_dir,
    review$source_artifact_path,
    sub("#.*$", "", review$evidence_url)
  ))) {
    expect_true(file.exists(structured_re_artifact_path(path)))
  }

  for (phrase in c(
    "T124 submitted exactly one host-separated DRAC Rorqual job 15112750",
    "source SHA guard passed",
    "library(drmTMB) passed",
    "devtools_available FALSE",
    "dependency drift exit 13",
    "no runner started",
    "no model formula",
    "no model fit",
    "no pdHess",
    "no Wald interval",
    "no profile interval",
    "no output rows",
    "no retained denominator",
    "no admission pass",
    "no coverage",
    "no support-cell status edit",
    "no inference_ready",
    "no supported",
    "no public support",
    "no REML",
    "no AI-REML",
    "no denominator pooling",
    "not a tier claim"
  )) {
    expect_true(any(grepl(phrase, review$claim_boundary, fixed = TRUE)))
  }
  for (phrase in c(
    "T125",
    "no-compute dependency-route review",
    "before any repeat execution",
    "prestage/install devtools",
    "avoid devtools::load_all",
    "host label drac_rorqual_q1mu_slope_spatial_t120_t122_packet_n5",
    "missing target",
    "fit error",
    "pdHess FALSE",
    "nonfinite Wald interval",
    "nonfinite profile interval",
    "source SHA drift",
    "dependency drift",
    "denominator drift"
  )) {
    expect_true(any(grepl(phrase, review$next_gate, fixed = TRUE)))
  }

  artifact_root <- paste0(
    "docs/dev-log/simulation-artifacts/",
    "2026-07-03-t124-spatial-drac-terminal"
  )
  terminal_status <- paste(readLines(structured_re_artifact_path(
    artifact_root,
    "remote/t124-terminal-status.tsv"
  ), warn = FALSE), collapse = "\n")
  expect_match(terminal_status, "devtools_available\tfailed\t13\tdependency_drift_devtools_missing_or_unloadable", fixed = TRUE)
  devtools_available <- paste(readLines(structured_re_artifact_path(
    artifact_root,
    "remote/devtools-availability.tsv"
  ), warn = FALSE), collapse = "\n")
  expect_match(devtools_available, "devtools_available\tFALSE", fixed = TRUE)
  missing_result <- paste(readLines(structured_re_artifact_path(
    artifact_root,
    "remote/missing-result-proof.tsv"
  ), warn = FALSE), collapse = "\n")
  expect_match(missing_result, "dependency_drift_devtools_missing_or_unloadable", fixed = TRUE)
  sacct <- paste(readLines(structured_re_artifact_path(
    artifact_root,
    "slurm/sacct-15112750.tsv"
  ), warn = FALSE), collapse = "\n")
  expect_match(sacct, "15112750|drmtmb-t124-model", fixed = TRUE)
  expect_match(sacct, "|FAILED|13:0|", fixed = TRUE)
  checksums <- paste(readLines(structured_re_artifact_path(
    artifact_root,
    "t124-local-inputs.sha256"
  ), warn = FALSE), collapse = "\n")
  expect_match(checksums, "structured-re-gaussian-mu-slope-tranche124-spatial-drac-model-smoke-execution-terminal-review.tsv", fixed = TRUE)
  expect_match(checksums, "missing-result-proof.tsv", fixed = TRUE)
  expect_match(checksums, "devtools-availability.tsv", fixed = TRUE)

  linked <- qseries[qseries$cell_id == "qseries_spatial_q1_mu_one_slope", ]
  expect_equal(nrow(linked), 1L)
  expect_equal(linked$fit_status, "point_fit")
  expect_equal(linked$interval_status, "planned")
  expect_equal(linked$coverage_status, "planned")

  mu_queue <- queue[queue$queue_id == "qseries_queue_gaussian_mu_slope_shape_rule", ]
  expect_equal(mu_queue$primary_evidence, structured_re_latest_mu_queue_evidence())
  expect_match(mu_queue$readiness_state, "T124 submitted exactly one Rorqual job 15112750", fixed = TRUE)
  expect_match(mu_queue$required_preconditions, "T125 must be a no-compute dependency-route review", fixed = TRUE)
  expect_match(mu_queue$readiness_state, "T125 no-compute dependency-route review completed locally", fixed = TRUE)
  expect_match(mu_queue$required_preconditions, "T126 must be a no-compute patched-runner packet checkpoint", fixed = TRUE)
  expect_match(mu_queue$stop_rule, "Stop if T124 failed job 15112750 is counted as model evidence", fixed = TRUE)
  expect_match(mu_queue$stop_rule, "Stop if T125 route-review rows are treated as fit evidence", fixed = TRUE)
  expect_match(mu_queue$no_claims, "No Tranche 124 row is fit evidence", fixed = TRUE)
  expect_match(mu_queue$no_claims, "No Tranche 125 row is fit evidence", fixed = TRUE)
  expect_current_mu_queue_next_action(mu_queue)

  meeting <- discussions[
    discussions$meeting_id ==
      "meeting-2026-07-03-tranche124-mu-slope-spatial-drac-model-smoke-execution-terminal-review" &
      discussions$slice_id == "SC445",
  ]
  expect_setequal(
    meeting$member_id,
    c("ada", "rose", "fisher", "gauss", "noether", "grace", "curie", "boole", "emmy")
  )
  expect_true(all(meeting$evidence_path == structured_re_tranche124_mu_evidence()))
  blocking <- meeting$member_id %in% c("rose", "fisher", "gauss", "noether", "grace")
  expect_equal(meeting$stance[blocking], rep("block_until_done", sum(blocking)))
  expect_equal(meeting$stance[!blocking], rep("approve", sum(!blocking)))
  expect_equal(meeting$decision_status, rep("accepted", nrow(meeting)))
  expect_match(meeting$exact_claim[meeting$member_id == "rose"], "terminal dependency-drift evidence only", fixed = TRUE)
  expect_match(meeting$exact_claim[meeting$member_id == "rose"], "not a tier claim", fixed = TRUE)
  expect_match(meeting$exact_claim[meeting$member_id == "fisher"], "zero completed model replicates", fixed = TRUE)
  expect_match(meeting$exact_claim[meeting$member_id == "fisher"], "zero retained denominators", fixed = TRUE)
  expect_match(meeting$exact_claim[meeting$member_id == "gauss"], "devtools_available FALSE", fixed = TRUE)
  expect_match(meeting$exact_claim[meeting$member_id == "gauss"], "no pdHess", fixed = TRUE)
  expect_match(meeting$exact_claim[meeting$member_id == "noether"], "sd_mu_intercept/sd_mu_x", fixed = TRUE)
  expect_match(meeting$exact_claim[meeting$member_id == "noether"], "profile_targets absent", fixed = TRUE)
  expect_match(meeting$exact_claim[meeting$member_id == "grace"], "job 15112750 on rc31704", fixed = TRUE)
  expect_match(meeting$exact_claim[meeting$member_id == "grace"], "drac_rorqual_q1mu_slope_spatial_t120_t122_packet_n5", fixed = TRUE)
  expect_match(meeting$exact_claim[meeting$member_id == "grace"], "missing-result proof", fixed = TRUE)
})


test_that("Tranche 125 records no-compute dependency route review", {
  prior_review <- structured_re_read_dashboard_tsv(
