    )
  )
  expect_equal(review$decision_scope, rep("q1_mu_one_slope_spatial_drac_dependency_route_review", 12L))
  expect_equal(review$source_decision_id, rep("tranche124_spatial_mu_slope_tranche_summary", 12L))
