  expect_equal(review$source_sidecar_file, rep(structured_re_tranche124_mu_evidence(), 12L))
  expect_equal(as.character(review$job_id), rep("no_new_job_T125_no_compute", 12L))
  expect_equal(review$observed_rorqual_host, rep("none_no_host_command_in_tranche125", 12L))
  expect_equal(review$remote_exit_code, rep("not_submitted_no_host_command", 12L))
  expect_equal(review$dependency_probe_status, rep("T124_library_drmTMB_passed_devtools_available_FALSE", 12L))
  expect_equal(review$missing_dependency_status, rep("devtools_route_rejected_installed_package_route_selected", 12L))
  expect_equal(review$load_status, rep("no_host_load_attempted_T125_selects_future_library_drmTMB_route", 12L))
  expect_equal(review$sbatch_status, rep("not_submitted_no_compute_route_review", 12L))
  expect_equal(review$model_command_status, rep("not_started_no_compute_route_review", 12L))
  expect_equal(review$denominator_status, rep("no_new_denominator", 12L))
  expect_equal(review$coverage_decision, rep("coverage_not_authorized", 12L))
  expect_equal(review$promotion_decision, rep("do_not_promote", 12L))
  expect_equal(review$support_cell_decision, rep("unchanged_point_fit_planned_planned", 12L))

  for (path in unique(c(
    review$source_sidecar_file,
    review$local_artifact_dir,
    review$source_artifact_path,
    sub("#.*$", "", review$evidence_url)
  ))) {
    expect_true(file.exists(structured_re_artifact_path(path)))
  }

  for (phrase in c(
    "T125 is no-compute dependency-route review only",
    "library(drmTMB)",
    "devtools_available FALSE",
    "--load-source=false installed-package route",
    "runner_hash_84a335abddbd04f74c30daeb448af37e8d713471f71b2656c2ab41c4e85558b9",
    "wrapper_hash_ea63c6fe0a4423296f48f2a11ec75232ce2e3ff37eb0b52bc3f48db5287bc5a2",
