    "no inference_ready",
    "no supported",
    "not a tier claim"
  )) {
    expect_true(any(grepl(phrase, review$claim_boundary, fixed = TRUE)))
  }
  for (phrase in c(
    "T126 no-compute patched-runner packet checkpoint",
    "--load-source=false",
    "library(drmTMB) installed-package route",
    "source SHA 56add7f04fab7bec57a42e56eaeb090dff491863",
    "host label drac_rorqual_q1mu_slope_spatial_t120_t122_packet_n5",
    "Rose/Fisher/Gauss/Noether/Grace approval",
    "missing target",
    "fit error",
    "pdHess FALSE",
    "nonfinite Wald interval",
    "nonfinite profile interval",
    "validator drift"
  )) {
    expect_true(any(grepl(phrase, review$next_gate, fixed = TRUE)))
  }

  artifact_root <- paste0(
    "docs/dev-log/simulation-artifacts/",
    "2026-07-03-gaussian-mu-slope-tranche125-spatial-drac-dependency-route-review"
  )
  review_txt <- paste(readLines(structured_re_artifact_path(
    artifact_root,
    "t125-dependency-route-review.txt"
  ), warn = FALSE), collapse = "\n")
  expect_match(review_txt, "selected_route=installed_package_library_drmTMB_via_load_source_false", fixed = TRUE)
  expect_match(review_txt, "compute_status=no_ssh_no_remote_copy_no_sbatch_no_allocation_no_model", fixed = TRUE)
  runner_dry <- paste(readLines(structured_re_artifact_path(
    artifact_root,
    "t125-runner-dry-run-load-source-false.tsv"
  ), warn = FALSE), collapse = "\n")
  expect_match(runner_dry, "dry_run_only_no_fit_no_host_command", fixed = TRUE)
  expect_match(runner_dry, "load-source=false is an explicit installed-package route", fixed = TRUE)
  wrapper_manifest <- paste(readLines(structured_re_artifact_path(
    artifact_root,
    "t125-wrapper-manifest-load-source-false.tsv"
  ), warn = FALSE), collapse = "\n")
  expect_match(wrapper_manifest, "manifest_only_no_rscript_no_model_no_denominator", fixed = TRUE)
  checksums <- paste(readLines(structured_re_artifact_path(
    artifact_root,
    "t125-local-inputs.sha256"
  ), warn = FALSE), collapse = "\n")
  expect_match(checksums, "structured-re-gaussian-mu-slope-tranche125-spatial-drac-dependency-route-review.tsv", fixed = TRUE)
  expect_match(checksums, "84a335abddbd04f74c30daeb448af37e8d713471f71b2656c2ab41c4e85558b9", fixed = TRUE)
  expect_match(checksums, "ea63c6fe0a4423296f48f2a11ec75232ce2e3ff37eb0b52bc3f48db5287bc5a2", fixed = TRUE)

  runner <- paste(readLines(structured_re_artifact_path(
    "tools/run-gaussian-mu-slope-tranche85-spatial-drac-host-smoke.R"
  ), warn = FALSE), collapse = "\n")
  wrapper <- paste(readLines(structured_re_artifact_path(
    "tools/run-gaussian-mu-slope-tranche85-spatial-drac-host-smoke.sh"
  ), warn = FALSE), collapse = "\n")
  expect_match(runner, "--load-source=true|false", fixed = TRUE)
  expect_match(runner, "library(drmTMB)", fixed = TRUE)
  expect_match(runner, "devtools::load_all", fixed = TRUE)
  expect_match(wrapper, "DRMTMB_Q1MU_SLOPE_T85_LOAD_SOURCE", fixed = TRUE)
  expect_match(wrapper, "--load-source=\"${LOAD_SOURCE}\"", fixed = TRUE)

  linked <- qseries[qseries$cell_id == "qseries_spatial_q1_mu_one_slope", ]
  expect_equal(nrow(linked), 1L)
  expect_equal(linked$fit_status, "point_fit")
  expect_equal(linked$interval_status, "planned")
  expect_equal(linked$coverage_status, "planned")

  mu_queue <- queue[queue$queue_id == "qseries_queue_gaussian_mu_slope_shape_rule", ]
  expect_equal(mu_queue$primary_evidence, structured_re_latest_mu_queue_evidence())
  expect_match(mu_queue$readiness_state, "T125 no-compute dependency-route review completed locally", fixed = TRUE)
  expect_match(mu_queue$required_preconditions, "T126 must be a no-compute patched-runner packet checkpoint", fixed = TRUE)
  expect_match(mu_queue$stop_rule, "Stop if T125 route-review rows are treated as fit evidence", fixed = TRUE)
  expect_match(mu_queue$no_claims, "No Tranche 125 row is fit evidence", fixed = TRUE)
  expect_current_mu_queue_next_action(mu_queue)

  meeting <- discussions[
    discussions$meeting_id ==
      "meeting-2026-07-03-tranche125-mu-slope-spatial-drac-dependency-route-review" &
      discussions$slice_id == "SC446",
  ]
  expect_setequal(
    meeting$member_id,
    c("ada", "rose", "fisher", "gauss", "noether", "grace", "curie", "boole", "emmy")
  )
  expect_true(all(meeting$evidence_path == structured_re_tranche125_mu_evidence()))
  blocking <- meeting$member_id %in% c("rose", "fisher", "gauss", "noether", "grace")
  expect_equal(meeting$stance[blocking], rep("block_until_done", sum(blocking)))
  expect_equal(meeting$stance[!blocking], rep("approve", sum(!blocking)))
  expect_equal(meeting$decision_status, rep("accepted", nrow(meeting)))
  expect_match(meeting$exact_claim[meeting$member_id == "rose"], "route-review evidence only", fixed = TRUE)
  expect_match(meeting$exact_claim[meeting$member_id == "rose"], "not a tier claim", fixed = TRUE)
  expect_match(meeting$exact_claim[meeting$member_id == "fisher"], "zero completed model replicates", fixed = TRUE)
  expect_match(meeting$exact_claim[meeting$member_id == "fisher"], "zero retained denominators", fixed = TRUE)
  expect_match(meeting$exact_claim[meeting$member_id == "gauss"], "devtools_available FALSE", fixed = TRUE)
