  expect_match(meeting$exact_claim[meeting$member_id == "noether"], "sd_mu_intercept/sd_mu_x", fixed = TRUE)
  expect_match(meeting$exact_claim[meeting$member_id == "noether"], "profile_targets absent", fixed = TRUE)
  expect_match(meeting$exact_claim[meeting$member_id == "grace"], "56add7f04fab7bec57a42e56eaeb090dff491863", fixed = TRUE)
  expect_match(meeting$exact_claim[meeting$member_id == "grace"], "drac_rorqual_q1mu_slope_spatial_t120_t122_packet_n5", fixed = TRUE)
  expect_match(meeting$exact_claim[meeting$member_id == "grace"], "84a335abddbd04f74c30daeb448af37e8d713471f71b2656c2ab41c4e85558b9", fixed = TRUE)
  expect_match(meeting$exact_claim[meeting$member_id == "grace"], "ea63c6fe0a4423296f48f2a11ec75232ce2e3ff37eb0b52bc3f48db5287bc5a2", fixed = TRUE)
