  expect_match(row$required_preconditions, "Before any T130/T129 execution", fixed = TRUE)
  expect_match(row$stop_rule, "Stop if T130 executes without approval", fixed = TRUE)
  expect_match(row$next_action, "Prefer Q-Series tooling speedup", fixed = TRUE)

  meeting <- discussions[
    discussions$meeting_id ==
