      discussions$slice_id == "SC448",
    ,
    drop = FALSE
  ]
  expect_equal(
    sort(meeting$member_id),
    c("ada", "boole", "curie", "emmy", "fisher", "gauss", "grace", "noether", "rose")
  )
  expect_equal(meeting$evidence_path, rep(structured_re_tranche128_q2_evidence(), 9L))
  expect_equal(meeting$decision_status, rep("accepted", 9L))
  blocking <- meeting$member_id %in% c("rose", "fisher", "gauss", "noether", "grace")
  expect_equal(meeting$stance[blocking], rep("block_until_done", 5L))
  expect_equal(meeting$stance[!blocking], rep("approve", 4L))
  expect_match(
    meeting$exact_claim[meeting$member_id == "rose"],
    "route-design evidence only",
    fixed = TRUE
  )
  expect_match(
    meeting$exact_claim[meeting$member_id == "fisher"],
    "zero new replicates",
    fixed = TRUE
  )
  expect_match(
    meeting$exact_claim[meeting$member_id == "gauss"],
    "finite but n=1 spatial g32 profile/Wald smoke",
    fixed = TRUE
  )
  expect_match(
    meeting$exact_claim[meeting$member_id == "noether"],
    "target identity separate",
    fixed = TRUE
  )
  expect_match(
    meeting$exact_claim[meeting$member_id == "grace"],
    "no host event",
    fixed = TRUE
  )
  structured_re_expect_all_match(meeting$next_gate, "T129")
})

