test_that("q-series v1 readiness reset separates basic-working from support", {
  reset <- structured_re_read_dashboard_tsv(
    "structured-re-q-series-v1-readiness-reset.tsv"
  )
  qseries <- structured_re_read_dashboard_tsv(
    "structured-re-q-series-support-cells.tsv"
  )
  release <- structured_re_read_dashboard_tsv(
    "structured-re-q-series-v1-release-ledger.tsv"
  )
  status_path <- structured_re_artifact_path(
    "docs",
    "dev-log",
    "release-audits",
    "q-series-v1-release-status.md"
  )
  expect_true(file.exists(status_path))
  status_text <- paste(readLines(status_path, warn = FALSE), collapse = " ")
  status_text <- gsub("[[:space:]]+", " ", status_text)

  expect_named(
    reset,
    c(
      "readiness_id",
      "readiness_scope",
      "row_count",
      "gaussian_rows",
      "non_gaussian_rows",
      "v1_tier",
      "current_evidence",
      "validation_deferred",
      "v1_decision",
      "claim_boundary",
      "next_action"
    )
  )
  expect_named(
    release,
    c(
      "cell_id",
      "formula_cell",
      "family_class",
      "family",
      "structure_provider",
      "dimension_pattern",
      "endpoint_set",
      "slope_class",
      "fit_status",
      "interval_status",
      "coverage_status",
      "authority_status",
      "v1_track",
      "v1_priority",
      "v1_release_role",
      "post_v1_gate",
      "claim_boundary",
      "evidence_url",
      "next_gate"
    )
  )
  expect_equal(nrow(reset), 8L)
  expect_equal(nrow(release), nrow(qseries))
  expect_setequal(reset$readiness_id, c(
    "qseries_v1_goal_reset",
    "qseries_v1_gaussian_basic_working",
    "qseries_v1_gaussian_inference_ready",
    "qseries_v1_gaussian_deferred_validation",
    "qseries_v1_nongaussian_basic_recovery",
    "qseries_v1_nongaussian_deferred",
    "qseries_v1_support_deferred",
    "qseries_v1_tooling_speedup"
  ))

  gaussian <- qseries$family_class == "gaussian"
  non_gaussian <- qseries$family_class == "non_gaussian"
  exact_ir <- gaussian &
    qseries$interval_status == "inference_ready" &
    qseries$coverage_status == "inference_ready"
  gaussian_basic <- gaussian &
    qseries$fit_status %in% c("point_fit", "supported", "diagnostic_only")
  gaussian_deferred <- gaussian &
    qseries$fit_status %in% c("planned", "unsupported")
  nongaussian_recovery <- non_gaussian & qseries$fit_status == "point_fit"
  nongaussian_deferred <- non_gaussian &
    qseries$fit_status %in% c("planned", "unsupported")

  release_by_cell <- release[match(qseries$cell_id, release$cell_id), , drop = FALSE]
  expect_false(anyNA(match(qseries$cell_id, release$cell_id)))
  copied_fields <- c(
    "cell_id",
    "formula_cell",
    "family_class",
    "family",
    "structure_provider",
    "dimension_pattern",
    "endpoint_set",
    "slope_class",
    "fit_status",
    "interval_status",
    "coverage_status",
    "authority_status",
    "evidence_url",
    "next_gate"
  )
  for (field in copied_fields) {
    expect_equal(release_by_cell[[field]], qseries[[field]])
  }
  expected_track <- rep("basic_distribution_post_v1_design", nrow(qseries))
  expected_track[non_gaussian & qseries$fit_status == "point_fit"] <-
    "basic_distribution_recovery"
  expected_track[gaussian & qseries$fit_status %in% c("planned", "unsupported")] <-
    "gaussian_post_v1_validation"
  expected_track[gaussian & qseries$fit_status %in% c("point_fit", "supported", "diagnostic_only")] <-
    "gaussian_basic_working"
  expected_track[exact_ir] <- "gaussian_inference_anchor"
  expect_equal(release_by_cell$v1_track, expected_track)
  expect_equal(sum(release$v1_track == "gaussian_inference_anchor"), sum(exact_ir))
  expect_equal(
    sum(release$v1_track == "gaussian_basic_working") +
      sum(release$v1_track == "gaussian_inference_anchor"),
    sum(gaussian_basic)
  )
  expect_equal(sum(release$v1_track == "gaussian_post_v1_validation"), sum(gaussian_deferred))
  expect_equal(sum(release$v1_track == "basic_distribution_recovery"), sum(nongaussian_recovery))
  expect_equal(sum(release$v1_track == "basic_distribution_post_v1_design"), sum(nongaussian_deferred))
  expect_setequal(
    release$v1_priority,
    c("P1", "P2", "P3", "P4", "P5")
  )

  value <- function(id, field) reset[reset$readiness_id == id, field]
  expect_equal(as.integer(value("qseries_v1_goal_reset", "row_count")), nrow(qseries))
  expect_equal(as.integer(value("qseries_v1_goal_reset", "gaussian_rows")), sum(gaussian))
  expect_equal(as.integer(value("qseries_v1_goal_reset", "non_gaussian_rows")), sum(non_gaussian))
  expect_equal(as.integer(value("qseries_v1_gaussian_basic_working", "row_count")), sum(gaussian_basic))
  expect_equal(as.integer(value("qseries_v1_gaussian_inference_ready", "row_count")), sum(exact_ir))
