  expect_equal(run_log$shard_id, "all-targets")
  expect_equal(run_log$provider_filter, "all")
  expect_equal(run_log$endpoint_member_filter, "all")
  expect_equal(run_log$execution_status, "validated_not_executed")
  expect_equal(run_log$scheduler_status, "dry_run_not_submitted")
  expect_equal(run_log$compute_status, "not_executed")
  expect_equal(run_log$denominator_status, "runner_contract_only")
  expect_equal(run_log$mcse_threshold_status, "not_met_by_sr150")
  expect_equal(run_log$coverage_evaluable, FALSE)
  expect_equal(run_log$coverage_status, "not_evaluated")
  expect_equal(run_log$interval_claim_status, "diagnostic_only")
  expect_equal(run_log$status, "covered")

  for (provider in c("phylo", "spatial", "animal", "relmat")) {
    shard_id <- paste0("provider-", provider)
    shard_manifest <- utils::read.delim(
      structured_re_artifact_path(
        "docs",
        "dev-log",
        "simulation-artifacts",
        "2026-06-25-sigma-slope-coverage-runner-contract",
        paste0(
          "structured-re-sigma-slope-coverage-runner-target-manifest-",
          shard_id,
          ".tsv"
        )
      ),
      sep = "\t",
      quote = "",
      check.names = FALSE,
      stringsAsFactors = FALSE
    )
    shard_log <- utils::read.delim(
      structured_re_artifact_path(
        "docs",
        "dev-log",
        "simulation-artifacts",
        "2026-06-25-sigma-slope-coverage-runner-contract",
        paste0(
          "structured-re-sigma-slope-coverage-runner-run-log-",
          shard_id,
          ".tsv"
        )
      ),
      sep = "\t",
      quote = "",
      check.names = FALSE,
      stringsAsFactors = FALSE
    )
    expected_n <- sum(runner$structured_type == provider)
    expect_equal(nrow(shard_manifest), expected_n)
    expect_equal(nrow(shard_log), 1L)
    expect_equal(shard_manifest$structured_type, rep(provider, expected_n))
    expect_equal(shard_manifest$mode, rep("dry-run", expected_n))
    expect_equal(
      shard_manifest$selected_manifest,
      rep(
        paste(
          "docs/dev-log/simulation-artifacts",
          "2026-06-25-sigma-slope-coverage-runner-contract",
          paste0(
            "structured-re-sigma-slope-coverage-runner-target-manifest-",
            shard_id,
            ".tsv"
          ),
          sep = "/"
        ),
        expected_n
      )
    )
    expect_equal(
      shard_manifest$run_log,
      rep(
        paste(
          "docs/dev-log/simulation-artifacts",
          "2026-06-25-sigma-slope-coverage-runner-contract",
          paste0(
            "structured-re-sigma-slope-coverage-runner-run-log-",
            shard_id,
            ".tsv"
          ),
          sep = "/"
        ),
        expected_n
      )
    )
    expect_false(any(
      shard_manifest$selected_manifest %in% runner$selected_manifest
    ))
    expect_false(any(shard_manifest$run_log %in% runner$run_log))
    expect_equal(shard_log$selected_targets, expected_n)
    expect_equal(shard_log$shard_id, shard_id)
    expect_equal(shard_log$provider_filter, provider)
    expect_equal(shard_log$endpoint_member_filter, "all")
    expect_equal(shard_log$execution_status, "validated_not_executed")
    expect_equal(shard_log$compute_status, "not_executed")
    expect_equal(shard_log$denominator_status, "runner_contract_only")
    expect_equal(shard_log$coverage_evaluable, FALSE)
    expect_equal(shard_log$coverage_status, "not_evaluated")
  }
})

test_that("structured RE PR stack merge-readiness keeps the stack ordered", {
  stack <- structured_re_read_dashboard_tsv(
    "structured-re-pr-stack-merge-readiness.tsv"
  )
  snapshot <- utils::read.delim(
    structured_re_artifact_path(
      "docs",
      "dev-log",
      "simulation-artifacts",
      "2026-06-25-pr-stack-merge-readiness",
      "structured-re-pr-stack-merge-readiness-snapshot.tsv"
    ),
    sep = "\t",
    quote = "",
    check.names = FALSE,
    stringsAsFactors = FALSE
  )
  run_log <- utils::read.delim(
    structured_re_artifact_path(
      "docs",
      "dev-log",
      "simulation-artifacts",
      "2026-06-25-pr-stack-merge-readiness",
      "structured-re-pr-stack-merge-readiness-run-log.tsv"
    ),
    sep = "\t",
    quote = "",
    check.names = FALSE,
    stringsAsFactors = FALSE
  )

  expect_named(
    stack,
    c(
      "stack_row_id",
      "merge_order",
      "pr_number",
      "title",
      "base_ref",
      "head_ref",
      "head_sha",
      "pr_url",
      "observed_utc",
      "draft_status",
      "merge_state_status",
      "pr_rollup_status",
      "commit_check_status",
      "r_cmd_check_run_id",
      "platform_success_count",
      "platform_successes",
      "merge_gate",
      "retarget_requirement",
      "normal_pr_check_requirement",
      "merge_action",
      "compute_status",
      "drac_status",
      "totoro_status",
      "coverage_claim_status",
      "interval_claim_status",
      "reml_claim_status",
      "public_support_status",
      "stack_status",
      "dashboard_snapshot",
      "artifact_snapshot",
      "run_log",
      "evidence_url",
      "claim_boundary",
      "next_gate"
    )
  )
  expect_equal(snapshot, stack)
  expected_prs <- 639:663
  expected_stack_rows <- length(expected_prs)
  expected_stacked_rows <- expected_stack_rows - 1L
  expect_equal(nrow(stack), expected_stack_rows)
  expect_equal(nrow(run_log), 1L)
  expect_equal(stack$merge_order, seq_len(expected_stack_rows))
  expect_equal(stack$pr_number, expected_prs)
  expect_equal(
    stack$stack_row_id,
    paste0("structured_re_pr_stack_merge_", stack$pr_number)
  )
  expect_equal(stack$base_ref[[1L]], "main")
  expect_equal(stack$base_ref[-1L], stack$head_ref[-nrow(stack)])
  expect_equal(
    stack$pr_url,
    paste0("https://github.com/itchyshin/drmTMB/pull/", stack$pr_number)
  )
  expect_equal(stack$draft_status, rep("draft", expected_stack_rows))
  expect_equal(stack$merge_state_status, rep("CLEAN", expected_stack_rows))
  expect_equal(
    stack$pr_rollup_status[[1L]],
    "attached_pr_checks_green_on_main_base"
  )
  expect_equal(
    stack$pr_rollup_status[-1L],
    rep(
      "commit_checks_green_pr_rollup_empty_on_stacked_base",
      expected_stacked_rows
    )
  )
  expect_equal(
    stack$commit_check_status,
    rep("three_platform_success", expected_stack_rows)
  )
  expect_equal(stack$platform_success_count, rep(3L, expected_stack_rows))
  structured_re_expect_all_match(stack$platform_successes, "ubuntu-latest")
  structured_re_expect_all_match(stack$platform_successes, "macos-latest")
  structured_re_expect_all_match(stack$platform_successes, "windows-latest")
  expect_equal(
    stack$merge_gate,
    rep("human_approval_required", expected_stack_rows)
  )
  expect_equal(
    stack$retarget_requirement[[1L]],
    "none_first_pr_targets_main"
  )
  expect_equal(
    stack$retarget_requirement[-1L],
    rep("retarget_to_main_after_previous_merge", expected_stacked_rows)
  )
  expect_equal(
    stack$normal_pr_check_requirement[[1L]],
    "already_attached_to_main_base"
  )
  expect_equal(
    stack$normal_pr_check_requirement[-1L],
    rep("rerun_after_retarget_to_main", expected_stacked_rows)
  )
  expect_equal(stack$compute_status, rep("not_executed", expected_stack_rows))
  expect_equal(stack$drac_status, rep("not_submitted", expected_stack_rows))
  expect_equal(stack$totoro_status, rep("not_submitted", expected_stack_rows))
  expect_equal(
    stack$coverage_claim_status,
    rep("not_evaluated", expected_stack_rows)
  )
  expect_equal(
    stack$interval_claim_status,
    rep("not_promoted", expected_stack_rows)
  )
  expect_equal(
    stack$reml_claim_status,
    rep("not_promoted", expected_stack_rows)
  )
  expect_equal(
    stack$public_support_status,
    rep("not_promoted", expected_stack_rows)
  )
  expect_equal(
    stack$stack_status,
    rep("merge_readiness_snapshot", expected_stack_rows)
  )
  expect_equal(
    stack$dashboard_snapshot,
    rep(
      "docs/dev-log/dashboard/structured-re-pr-stack-merge-readiness.tsv",
      expected_stack_rows
    )
  )
  expect_equal(
    stack$artifact_snapshot,
    rep(
      paste(
        "docs/dev-log/simulation-artifacts",
        "2026-06-25-pr-stack-merge-readiness",
        "structured-re-pr-stack-merge-readiness-snapshot.tsv",
        sep = "/"
      ),
      expected_stack_rows
    )
  )
  expect_equal(
    stack$run_log,
    rep(
      paste(
        "docs/dev-log/simulation-artifacts",
        "2026-06-25-pr-stack-merge-readiness",
        "structured-re-pr-stack-merge-readiness-run-log.tsv",
        sep = "/"
      ),
      expected_stack_rows
    )
  )

  structured_re_expect_all_match(
    stack$claim_boundary,
    "merge-readiness snapshot only"
  )
  structured_re_expect_all_match(stack$claim_boundary, "PRs remain draft")
  structured_re_expect_all_match(stack$claim_boundary, "no PR was undrafted")
  structured_re_expect_all_match(stack$claim_boundary, "no PR was merged")
  structured_re_expect_all_match(
    stack$claim_boundary,
    "no Totoro job submitted"
  )
  structured_re_expect_all_match(stack$claim_boundary, "no DRAC job submitted")
  structured_re_expect_all_match(
    stack$claim_boundary,
    "no coverage-evaluable denominator evidence"
  )
  structured_re_expect_all_match(
    stack$claim_boundary,
    "no MCSE-calibrated coverage"
  )
  structured_re_expect_all_match(
    stack$claim_boundary,
    "no interval reliability"
  )
  structured_re_expect_all_match(stack$claim_boundary, "no q4 REML")
  structured_re_expect_all_match(stack$claim_boundary, "no native-TMB q4 REML")
  structured_re_expect_all_match(stack$claim_boundary, "no q4 AI-REML")
  structured_re_expect_all_match(stack$claim_boundary, "no HSquared AI-REML")
  structured_re_expect_all_match(stack$claim_boundary, "no non-Gaussian REML")
  structured_re_expect_all_match(
    stack$claim_boundary,
    "no broad bridge support"
  )
  structured_re_expect_all_match(stack$claim_boundary, "no public support")
  structured_re_expect_all_match(stack$claim_boundary, "no SR150 readiness")
  structured_re_expect_all_match(stack$next_gate, "Ask Shinichi")
  structured_re_expect_all_match(stack$next_gate, "merge from PR #639 upward")
  structured_re_expect_all_match(
    stack$next_gate,
    "retarget the next PR to main"
  )
  structured_re_expect_all_match(stack$next_gate, "rerun normal PR checks")
  structured_re_expect_all_match(
    stack$next_gate,
    "rerun mission-control validation"
  )
  structured_re_expect_all_match(stack$next_gate, "return to sigma-slope")
  structured_re_expect_all_match(stack$next_gate, "relmat runtime slices")

  expect_equal(run_log$mode, "dry-run")
  expect_equal(run_log$stack_rows, expected_stack_rows)
  expect_equal(run_log$first_pr, min(expected_prs))
  expect_equal(run_log$last_pr, max(expected_prs))
  expect_equal(run_log$draft_rows, expected_stack_rows)
  expect_equal(run_log$clean_rows, expected_stack_rows)
  expect_equal(run_log$commit_check_success_rows, expected_stack_rows)
  expect_equal(run_log$attached_pr_rollup_rows, 1L)
  expect_equal(run_log$stacked_pr_rollup_empty_rows, expected_stacked_rows)
  expect_equal(run_log$execution_status, "validated_snapshot_not_executed")
  expect_equal(run_log$merge_status, "not_merged")
  expect_equal(run_log$compute_status, "not_executed")
  expect_equal(run_log$drac_status, "not_submitted")
  expect_equal(run_log$totoro_status, "not_submitted")
  expect_equal(run_log$status, "covered")
  expect_match(run_log$source_live_commands, "gh pr list", fixed = TRUE)
  expect_match(run_log$source_live_commands, "check-runs", fixed = TRUE)
})

