  expect_equal(nrow(run_log), 1L)
  expect_equal(run_log$mode, "execute")
  expect_equal(run_log$host_label, "local")
  expect_equal(run_log$provider, "all")
  expect_equal(run_log$n_rep, 5L)
  expect_equal(run_log$coverage_decision, "coverage_not_authorized")
  expect_equal(run_log$promotion_decision, "do_not_promote")

  expect_setequal(smoke$design_id, design$design_id)
  expect_equal(smoke$coverage_decision, rep("coverage_not_authorized", 16L))
  expect_equal(smoke$promotion_decision, rep("do_not_promote", 16L))
  expect_equal(smoke$host_label, rep("local", 16L))
  expect_equal(smoke$n_attempted, rep(5L, 16L))
  expect_equal(smoke$n_fit_error, rep(0L, 16L))
  expect_equal(raw$host_label, rep("local", 80L))
  expect_equal(raw$attempt_status, rep("fit_ok", 80L))
  expect_equal(raw$target_found, rep(TRUE, 80L))
  expect_equal(raw$coverage_decision, rep("coverage_not_authorized", 80L))
  expect_equal(raw$promotion_decision, rep("do_not_promote", 80L))
  expect_equal(
    raw$derived_correlation_interval_status,
    rep("derived_correlation_unavailable", 80L)
  )

  expected_decision <- function(n_pdhess, n_wald, n_profile) {
    if (n_pdhess == 5L && n_wald == 5L && n_profile == 5L) {
      "local_smoke_gate_passed_review_required_no_admission"
    } else {
      "not_admitted_local_smoke_gate_failed"
    }
  }
  for (i in seq_len(nrow(smoke))) {
    row <- smoke[i, , drop = FALSE]
    source <- design[design$design_id == row$design_id, , drop = FALSE]
    expect_equal(nrow(source), 1L)
    expect_equal(row$cell_id, source$cell_id)
    expect_equal(row$profile_target, source$profile_target)
    retained <- raw[raw$design_id == row$design_id, , drop = FALSE]
    expect_equal(nrow(retained), 5L)
    n_pdhess <- sum(retained$pdHess)
    n_wald <- sum(retained$wald_finite)
    n_profile <- sum(retained$profile_finite)
    expect_equal(row$n_pdhess, n_pdhess)
    expect_equal(row$pdhess_rate, n_pdhess / 5)
    expect_equal(row$n_wald_finite, n_wald)
    expect_equal(row$wald_finite_rate, n_wald / 5)
    expect_equal(row$n_profile_finite, n_profile)
    expect_equal(row$profile_finite_rate, n_profile / 5)
    expect_equal(
      row$admission_decision,
      expected_decision(n_pdhess, n_wald, n_profile)
    )
    expect_true(grepl(row$structured_type, row$next_gate, fixed = TRUE))
    expect_true(grepl(row$endpoint_member, row$next_gate, fixed = TRUE))
    expect_true(grepl(row$profile_target, row$next_gate, fixed = TRUE))
    expect_true(grepl("host provenance", row$next_gate, fixed = TRUE))
    expect_true(grepl(
      "before any coverage design",
      row$next_gate,
      fixed = TRUE
    ))
  }

  qseries <- qseries[
    match(unique(smoke$cell_id), qseries$cell_id),
    ,
    drop = FALSE
  ]
  expect_false(any(qseries$interval_status == "inference_ready"))
  expect_false(any(qseries$coverage_status == "inference_ready"))
  for (phrase in c(
    "Tranche 4 q4 location admission smoke only",
    "retained denominator recorded",
    "no coverage grid",
    "no interval reliability",
    "no inference_ready",
    "no supported",
    "no q4 REML",
    "no REML",
    "no AI-REML",
    "no q8 inference",
    "no derived-correlation interval claim",
    "no broad bridge support",
    "no public support"
  )) {
    expect_true(all(grepl(phrase, smoke$claim_boundary, fixed = TRUE)))
  }
})

test_that("Tranche 5 q4 admission review gates compute without promotion", {
  review <- structured_re_read_dashboard_tsv(
    "structured-re-q4-location-admission-tranche5-review.tsv"
  )
  smoke <- structured_re_read_dashboard_tsv(
    "structured-re-q4-location-admission-smoke.tsv"
  )
  roster <- structured_re_read_dashboard_tsv("member-roster.tsv")
  discussions <- structured_re_read_dashboard_tsv("member-discussions.tsv")

  expect_named(
    review,
    c(
      "review_id",
      "review_scope",
      "structured_type",
      "endpoint_member",
      "cell_id",
      "source_result_id",
      "profile_target",
      "n_attempted",
      "pdhess_rate",
      "wald_finite_rate",
      "profile_finite_rate",
      "admission_gate",
      "tranche5_review_decision",
      "compute_decision",
      "coverage_decision",
      "promotion_decision",
      "blocking_reviewers",
      "advisory_reviewers",
      "kim_rule",
      "rose_audit",
      "fisher_review",
      "gauss_review",
      "noether_review",
      "grace_review",
      "evidence_url",
      "claim_boundary",
      "next_gate"
    )
  )
  expect_equal(nrow(review), 21L)
  expect_equal(sum(review$review_scope == "target"), 16L)
  expect_equal(sum(review$review_scope == "provider_summary"), 4L)
  expect_equal(sum(review$review_scope == "tranche_summary"), 1L)
  expect_equal(
    review$coverage_decision,
    rep("coverage_not_authorized", nrow(review))
  )
  expect_equal(review$promotion_decision, rep("do_not_promote", nrow(review)))
  expect_equal(
    review$blocking_reviewers,
    rep("rose;fisher;gauss;noether;grace", nrow(review))
  )
  expect_equal(
    review$kim_rule,
    rep("least_compute_needed_for_honest_next_decision", nrow(review))
  )

  target <- review[review$review_scope == "target", , drop = FALSE]
  expect_setequal(target$source_result_id, smoke$result_id)
  for (i in seq_len(nrow(smoke))) {
    source <- smoke[i, , drop = FALSE]
    suffix <- sub(
      "^q4_location_admission_smoke_",
      "",
      source$result_id
    )
    row <- target[target$review_id == paste0("tranche5_review_", suffix), ]
    expect_equal(nrow(row), 1L)
    expect_equal(row$structured_type, source$structured_type)
    expect_equal(row$endpoint_member, source$endpoint_member)
    expect_equal(row$cell_id, source$cell_id)
    expect_equal(row$profile_target, source$profile_target)
    expect_equal(row$n_attempted, source$n_attempted)
    expect_equal(row$pdhess_rate, source$pdhess_rate)
    expect_equal(row$wald_finite_rate, source$wald_finite_rate)
    expect_equal(row$profile_finite_rate, source$profile_finite_rate)

    if (source$structured_type == "relmat") {
      expect_equal(
        row$tranche5_review_decision,
        "relmat_repeat_candidate_review_required_no_admission"
      )
      expect_equal(
        row$compute_decision,
        "host_separated_relmat_repeat_optional_after_blocking_reviews"
      )
      expect_match(row$next_gate, "host-separated relmat repeat", fixed = TRUE)
    } else {
      expect_match(row$tranche5_review_decision, "diagnostic_hold", fixed = TRUE)
      expect_match(row$compute_decision, "no_topup", fixed = TRUE)
      expect_match(row$next_gate, "before any repeat or coverage", fixed = TRUE)
    }
  }

  provider <- review[
    review$review_scope == "provider_summary",
    ,
    drop = FALSE
  ]
  expect_equal(provider$n_attempted, rep(20L, 4L))
  expect_equal(
    provider$structured_type,
    c("phylo", "spatial", "animal", "relmat")
  )
  expect_equal(provider$pdhess_rate, c(0.4, 0.6, 0.8, 1))
  expect_equal(provider$wald_finite_rate, c(0.4, 0.6, 0.8, 1))
  expect_equal(provider$profile_finite_rate, c(0.8, 0.8, 0.8, 1))
  expect_equal(
    provider$tranche5_review_decision,
    c(
      "provider_diagnostic_hold_no_repeat_no_admission",
      "provider_diagnostic_hold_no_repeat_no_admission",
      "provider_diagnostic_hold_failure_taxonomy_first_no_admission",
      "provider_repeat_candidate_review_required_no_admission"
    )
  )

  overall <- review[review$review_id == "tranche5_overall_decision", ]
  expect_equal(nrow(overall), 1L)
  expect_equal(
    overall$tranche5_review_decision,
    "zero_q4_rows_admitted_zero_coverage_jobs_authorized"
  )
  expect_equal(
    overall$compute_decision,
    "no_compute_until_blocking_reviews_accept_relmat_repeat"
  )
  expect_equal(overall$n_attempted, 80L)
  expect_match(overall$next_gate, "never q4 coverage", fixed = TRUE)

  for (phrase in c(
    "Tranche 5 q4 location admission review only",
    "no coverage grid",
    "no inference_ready",
    "no supported",
    "no q4 REML",
    "no AI-REML",
    "no derived-correlation interval claim",
    "no broad bridge support",
    "no public support"
  )) {
    expect_true(all(grepl(phrase, review$claim_boundary, fixed = TRUE)))
  }

  meeting <- discussions[
    discussions$meeting_id == "meeting-2026-07-01-tranche5-q4-admission",
    ,
    drop = FALSE
  ]
  expect_setequal(meeting$member_id, roster$member_id)
  blocking <- meeting[
    meeting$member_id %in% c("rose", "fisher", "gauss", "noether", "grace"),
    ,
    drop = FALSE
  ]
  expect_equal(blocking$stance, rep("block_until_done", 5L))
  expect_equal(blocking$decision_status, rep("accepted", 5L))
})

