  expect_equal(raw$promotion_decision, rep("do_not_promote", 20L))

  target <- repeat_tbl[repeat_tbl$repeat_scope == "target", , drop = FALSE]
  for (i in seq_len(nrow(target))) {
    row <- target[i, , drop = FALSE]
    retained <- raw[raw$endpoint_member == row$endpoint_member, , drop = FALSE]
    expect_equal(nrow(retained), 5L)
    expect_equal(row$n_attempted, 5L)
    expect_equal(row$n_fit_error, 0L)
    expect_equal(row$n_target_found, 5L)
    expect_equal(row$n_pdhess, sum(retained$pdHess))
    expect_equal(row$pdhess_rate, 1)
    expect_equal(row$n_wald_finite, sum(retained$wald_finite))
    expect_equal(row$wald_finite_rate, 1)
    expect_equal(row$n_profile_finite, sum(retained$profile_finite))
    expect_equal(row$profile_finite_rate, 1)
    expect_equal(row$n_boundary_estimate, sum(retained$boundary_estimate))
    expect_equal(
      row$admission_decision,
      "repeat_passed_review_required_no_admission"
    )
  }

  summary_rows <- repeat_tbl[
    repeat_tbl$repeat_scope %in% c("provider_summary", "run_summary"),
    ,
    drop = FALSE
  ]
  expect_equal(summary_rows$n_attempted, rep(20L, 2L))
  expect_equal(summary_rows$n_pdhess, rep(20L, 2L))
  expect_equal(summary_rows$pdhess_rate, rep(1, 2L))
  expect_equal(summary_rows$n_wald_finite, rep(20L, 2L))
  expect_equal(summary_rows$wald_finite_rate, rep(1, 2L))
  expect_equal(summary_rows$n_profile_finite, rep(20L, 2L))
  expect_equal(summary_rows$profile_finite_rate, rep(1, 2L))
  expect_equal(summary_rows$n_gradient_warning, rep(16L, 2L))
  expect_equal(summary_rows$n_profile_warning, rep(20L, 2L))

  for (phrase in c(
    "Tranche 5 relmat repeat smoke only",
    "host-separated Totoro evidence",
    "no denominator pooling",
    "no q4 admission",
    "no coverage grid",
    "no inference_ready",
    "no supported",
    "no q8 inference",
    "no derived-correlation interval claim",
    "no broad bridge support",
    "no public support"
  )) {
    expect_true(all(grepl(phrase, repeat_tbl$claim_boundary, fixed = TRUE)))
  }
  for (phrase in c(
    "q4 location admission smoke only",
    "retained denominator recorded",
    "no coverage grid",
    "no inference_ready",
    "no supported",
    "no q8 inference",
    "no derived-correlation interval claim",
    "no broad bridge support",
    "no public support"
  )) {
    expect_match(run_log$claim_boundary, phrase, fixed = TRUE)
  }
})

