    expect_equal(row$repeat_pdhess_rate, repeat_source$pdhess_rate)
    expect_equal(row$repeat_wald_finite_rate, repeat_source$wald_finite_rate)
    expect_equal(row$repeat_profile_finite_rate, repeat_source$profile_finite_rate)
    expect_equal(
      row$admission_decision,
      "admission_gate_met_for_coverage_design_review_only"
    )
    expect_match(row$next_gate, row$endpoint_member, fixed = TRUE)
