  expect_equal(summary_rows$repeat_n_attempted, rep(20L, 2L))
  expect_equal(summary_rows$local_pdhess_rate, rep(1, 2L))
  expect_equal(summary_rows$repeat_pdhess_rate, rep(1, 2L))
  expect_equal(summary_rows$repeat_n_gradient_warning, rep(16L, 2L))
  expect_equal(summary_rows$repeat_n_profile_warning, rep(20L, 2L))

  q_row <- qseries[
    qseries$cell_id == "qseries_relmat_q4_mu1_mu2_one_slope",
