    drop = FALSE
  ]
  expect_equal(nrow(q_row), 1L)
  expect_false(q_row$interval_status == "inference_ready")
  expect_false(q_row$coverage_status == "inference_ready")
  expect_false(q_row$authority_status == "supported")

  for (phrase in c(
