    "direct-SD admission gate met for coverage-design discussion",
    "host-separated Totoro evidence kept separate from local smoke",
    "no denominator pooling",
    "no coverage grid",
    "no interval reliability",
    "no inference_ready",
    "no supported",
    "no q4 REML",
    "no AI-REML",
    "no q8 inference",
    "no derived-correlation interval claim",
    "no broad bridge support",
    "no public support"
  )) {
    expect_true(all(grepl(phrase, review$claim_boundary, fixed = TRUE)))
  }
})

