    row <- target[i, , drop = FALSE]
    source <- contract[
      contract$contract_id == row$source_contract_id,
      ,
      drop = FALSE
    ]
    expect_equal(nrow(source), 1L)
    expect_equal(row$endpoint_member, source$endpoint_member)
    expect_equal(row$planned_shard, source$planned_shard)
    expect_match(row$totoro_command, "--execute", fixed = TRUE)
    expect_match(row$totoro_command, "rose_fisher_grace", fixed = TRUE)
    expect_match(
      row$totoro_command,
      paste0("--shards=", expected$planned_shard[[i]]),
      fixed = TRUE
    )
    expect_match(row$drac_command, "rose_fisher_grace", fixed = TRUE)
    expect_match(
      row$drac_command,
      paste0("--array=", expected$planned_shard[[i]]),
      fixed = TRUE
    )
    expect_match(row$drac_command, "DRMTMB_Q4LOC_N_REP=150", fixed = TRUE)
    expect_match(row$expected_outputs, expected$out_token[[i]], fixed = TRUE)
    expect_match(row$expected_outputs, expected$file_stem[[i]], fixed = TRUE)
    expect_match(row$run_log, paste0(expected$out_token[[i]], ".log"), fixed = TRUE)
    expect_match(row$next_gate, "stop before importing any result", fixed = TRUE)
  }

  summary_rows <- pack[
    pack$pack_scope %in% c("provider_summary", "tranche_summary"),
    ,
    drop = FALSE
  ]
  expect_equal(summary_rows$planned_shard, rep("13-16", 2L))
  expect_equal(summary_rows$seed_start, rep("980000:983000", 2L))
  expect_equal(summary_rows$seed_end, rep("980149:983149", 2L))
  expect_equal(summary_rows$n_rep, c(150L, 600L))
  expect_true(all(grepl("--shards=13,14,15,16", summary_rows$totoro_command, fixed = TRUE)))
  expect_true(all(grepl("--array=13-16", summary_rows$drac_command, fixed = TRUE)))

  for (phrase in c(
    "git rev-parse --short HEAD",
    "git status --short"
  )) {
    structured_re_expect_all_match(pack$source_provenance, phrase)
  }
  for (phrase in c("hostname", "Rscript --version", "sessionInfo")) {
    structured_re_expect_all_match(pack$host_provenance, phrase)
  }
  for (phrase in c(
    "Tranche 8 relmat q4 location host submission pack only",
    "exact commands prepared",
    "no Totoro execution",
    "no DRAC submission",
    "no coverage result",
    "no coverage-evaluable denominator",
    "no inference_ready",
    "no supported",
    "no q4 REML",
    "no REML",
    "no AI-REML",
    "no q8 inference",
    "no derived-correlation interval claim",
    "no denominator pooling",
    "no broad bridge support",
    "no public support"
  )) {
    structured_re_expect_all_match(pack$claim_boundary, phrase)
  }

  q_row <- qseries[
    qseries$cell_id == "qseries_relmat_q4_mu1_mu2_one_slope",
    ,
    drop = FALSE
  ]
  expect_equal(nrow(q_row), 1L)
  expect_false(q_row$coverage_status == "inference_ready")
  expect_false(q_row$authority_status == "supported")

  totoro_text <- paste(totoro_script, collapse = "\n")
  drac_text <- paste(drac_script, collapse = "\n")
  for (phrase in c(
    "DRMTMB_Q4LOC_EXECUTION_APPROVED",
    "rose_fisher_grace",
    "Only relmat q4 location shards 13,14,15,16 are allowed",
    "run-structured-re-q4-location-coverage-grid.R"
  )) {
    expect_match(totoro_text, phrase, fixed = TRUE)
  }
  for (phrase in c(
    "#SBATCH --array=13-16",
    "DRMTMB_Q4LOC_EXECUTION_APPROVED",
    "rose_fisher_grace",
    "Only relmat q4 location shards 13..16 are allowed",
    "DRMTMB_Q4LOC_N_REP",
    "run-structured-re-q4-location-coverage-grid.R"
  )) {
    expect_match(drac_text, phrase, fixed = TRUE)
  }

  meeting <- discussions[
    discussions$meeting_id ==
      "meeting-2026-07-01-tranche8-q4-relmat-host-pack",
    ,
    drop = FALSE
  ]
  expect_setequal(meeting$member_id, c("rose", "fisher", "grace"))
  expect_equal(meeting$stance, rep("block_until_done", 3L))
  expect_equal(meeting$decision_status, rep("accepted", 3L))
  expect_equal(
    meeting$evidence_path,
    rep(
      paste0(
        "docs/dev-log/dashboard/",
        "structured-re-q4-location-tranche8-relmat-host-submission-pack.tsv"
      ),
      3L
    )
  )
})

