    "bash tools/run-q4-location-relmat-pregrid-totoro.sh",
    "--execute",
    "--shards=13",
    "--attempt-temp-install",
    "2>&1"
  )
  fail_closed <- suppressWarnings(system(fail_closed_cmd, intern = TRUE))
  fail_closed_status <- attr(fail_closed, "status")
  if (is.null(fail_closed_status)) {
    fail_closed_status <- 0L
  }
  expect_equal(fail_closed_status, 2L)
  expect_match(
    paste(fail_closed, collapse = "\n"),
    "Refusing execution",
    fixed = TRUE
  )

  q_row <- qseries[
    qseries$cell_id == "qseries_relmat_q4_mu1_mu2_one_slope",
