  }
  for (source_id in result$source_tranche45_decision_id) {
    expect_equal(sum(decision$decision_id == source_id), 1L)
  }
  for (source_id in result$source_tranche44_review_id) {
    expect_equal(sum(terminal$review_id == source_id), 1L)
  }

  pdhess_true <- reps$pdHess == "TRUE"
  boundary <- reps$is_boundary == "TRUE"
  wald_finite <- reps$wald_status == "finite"
  expected_counts <- c(
    retained_n = nrow(reps),
    fit_ok_n = sum(reps$attempt_status == "fit_ok"),
    pdhess_true_n = sum(pdhess_true),
    pdhess_false_n = sum(!pdhess_true),
    boundary_n = sum(boundary),
    wald_finite_n = sum(wald_finite),
    wald_nonfinite_n = sum(!wald_finite),
    profile_finite_n = sum(reps$profile_status == "finite"),
    profile_failed_n = sum(reps$profile_conf_status == "profile_failed")
  )
  expect_equal(
    expected_counts,
    c(
      retained_n = 150L,
      fit_ok_n = 150L,
      pdhess_true_n = 112L,
      pdhess_false_n = 38L,
      boundary_n = 38L,
      wald_finite_n = 112L,
      wald_nonfinite_n = 38L,
      profile_finite_n = 149L,
      profile_failed_n = 1L
    )
