  expect_equal(profile_bad$is_boundary, TRUE)
  expect_equal(profile_bad$wald_status, "nonfinite")
  expect_equal(profile_bad$profile_message, "NA/NaN gradient evaluation")

  count_message_parts <- function(pattern, rows = reps) {
    sum(vapply(
      strsplit(rows$message, ";", fixed = TRUE),
      function(parts) sum(trimws(parts) == pattern),
      integer(1)
    ))
  }
  fallback_message <- '`drmTMB()` converged with the "BFGS" fallback optimizer after the `stats::nlminb()` presets did not. Inspect `fit$optimizer_attempts`.'
  expect_equal(count_message_parts(fallback_message), 117L)
  expect_equal(count_message_parts("NA/NaN function evaluation"), 71L)
  expect_equal(count_message_parts("NaNs produced"), 36L)
  expect_equal(count_message_parts(fallback_message, reps[boundary, , drop = FALSE]), 32L)
  expect_equal(count_message_parts(fallback_message, reps[!boundary, , drop = FALSE]), 85L)
  expect_equal(count_message_parts("NA/NaN function evaluation", reps[boundary, , drop = FALSE]), 53L)
  expect_equal(count_message_parts("NA/NaN function evaluation", reps[!boundary, , drop = FALSE]), 18L)
  expect_equal(count_message_parts("NaNs produced", reps[boundary, , drop = FALSE]), 36L)
  expect_equal(count_message_parts("NaNs produced", reps[!boundary, , drop = FALSE]), 0L)

  artifact_tree <- structured_re_artifact_path(
    "docs",
    "dev-log",
