  )
  tree_files <- list.files(artifact_tree, recursive = TRUE, full.names = FALSE)
  expect_equal(
    any(grepl("hessian|eigen|fit\\.rds|fit\\.rda|gradient", tree_files, ignore.case = TRUE)),
    FALSE
  )

  expect_equal(
    result$key_result,
    c(
      "all_38_boundary_rows_are_exactly_the_38_pdhess_false_and_wald_nonfinite_rows",
      "pdhess_true_iff_wald_finite_and_nonboundary;_pdhess_false_iff_wald_nonfinite_and_boundary",
      "bfgs_fallback_message_117_total_32_boundary_85_nonboundary;_nan_function_71_total_53_boundary_18_nonboundary;_nans_produced_36_all_boundary",
      "only_profile_failure_is_replicate119_seed980118_with_pdhess_false_boundary_wald_nonfinite_gradient_message",
      "imported_tree_contains_replicate_tsv_summary_tsv_log_session_source_provenance_but_no_fit_object_raw_hessian_gradient_or_eigenstructure_artifact",
      "boundary_mean_estimate_sd_0.4063_nonboundary_mean_0.4087_boundary_median_0.3988_nonboundary_median_0.3908_ranges_overlap_no_lower_sd_cluster_from_tsv_only",
      "pdhess_and_wald_rates_112_of_150_0.7467_fail_0.95_profile_149_of_150_does_not_override",
      "artifact_inspection_complete_route_should_park_or_require_new_design_not_compute"
    )
  )

  for (phrase in c(
